// frontend/src/components/workers/WorkerProfile.js
import React, { useState, useEffect } from 'react';
import { useParams, Link, useNavigate, useLocation } from 'react-router-dom';
import api from '../../services/api';
import { useAuth } from '../../contexts/AuthContext';
import { useAlert } from '../../contexts/AlertContext';
import './WorkerProfile.css';


const WorkerProfile = () => {
    const { id } = useParams();
    const navigate = useNavigate();
    const location = useLocation();
    const { user, updateUser } = useAuth();
    const alert = useAlert();
    const fromClient = location.state?.fromClient;
    const canHire = location.state?.canHire;

    const [worker, setWorker] = useState(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState('');
    const [isEditing, setIsEditing] = useState(false);
    const [uploadingImage, setUploadingImage] = useState(false);
    const [profileImage, setProfileImage] = useState(null);
    const [imagePreview, setImagePreview] = useState(null);

    const [profileData, setProfileData] = useState({
        name: '',
        email: '',
        phone: '',
        township: '',
        address: '',
        primary_skill: '',
        skills: [],
        experience_years: 0,
        hourly_rate_min: 100,
        hourly_rate_max: 300,
        available_days: '',
        available_hours: '',
        travel_radius_km: 5,
        bio: ''
    });

    const [newSkill, setNewSkill] = useState('');
    const [updating, setUpdating] = useState(false);
    const [updateSuccess, setUpdateSuccess] = useState('');

    const [passwordData, setPasswordData] = useState({
        current_password: '',
        new_password: '',
        confirm_password: ''
    });

    const [showPasswordModal, setShowPasswordModal] = useState(false);
    const [showDeleteModal, setShowDeleteModal] = useState(false);
    const [activeTab, setActiveTab] = useState('profile');

    // Get navigation state
    const fromJob = location.state?.from === 'job';
    const jobId = location.state?.jobId;
    const jobTitle = location.state?.jobTitle;

    useEffect(() => {
        loadWorkerProfile();
    }, [id]);

    const loadWorkerProfile = async () => {
        setLoading(true);
        try {
            const response = await api.get(`/workers/${id}`);
            if (response.data.success) {
                setWorker(response.data.data);
                setProfileData({
                    name: response.data.data.name || '',
                    email: response.data.data.email || '',
                    phone: response.data.data.phone || '',
                    township: response.data.data.township || '',
                    address: response.data.data.address || '',
                    primary_skill: response.data.data.primary_skill || '',
                    skills: response.data.data.skills || [],
                    experience_years: response.data.data.experience_years || 0,
                    hourly_rate_min: response.data.data.hourly_rate_min || 100,
                    hourly_rate_max: response.data.data.hourly_rate_max || 300,
                    available_days: response.data.data.available_days || '',
                    available_hours: response.data.data.available_hours || '',
                    travel_radius_km: response.data.data.travel_radius_km || 5,
                    bio: response.data.data.bio || ''
                });

                if (response.data.data.profile_picture) {
                    setImagePreview(response.data.data.profile_picture);
                }
            } else {
                setError('Worker not found');
            }
        } catch (error) {
            console.error('Error loading worker:', error);
            setError('Failed to load worker profile');
        } finally {
            setLoading(false);
        }
    };

    const handleInputChange = (e) => {
        const { name, value, type } = e.target;
        setProfileData(prev => ({
            ...prev,
            [name]: type === 'number' ? (value ? parseInt(value) : 0) : value
        }));
    };

    const handlePasswordChange = (e) => {
        const { name, value } = e.target;
        setPasswordData(prev => ({
            ...prev,
            [name]: value
        }));
    };

    // Add a new skill
    const handleAddSkill = () => {
        if (newSkill.trim() && !profileData.skills.includes(newSkill.trim())) {
            setProfileData(prev => ({
                ...prev,
                skills: [...prev.skills, newSkill.trim()]
            }));
            setNewSkill('');
        }
    };

    // Remove a skill
    const handleRemoveSkill = (skillToRemove) => {
        setProfileData(prev => ({
            ...prev,
            skills: prev.skills.filter(skill => skill !== skillToRemove)
        }));
    };

    const handleImageChange = (e) => {
        const file = e.target.files[0];
        if (file) {
            // Validate file type
            if (!file.type.match(/image.*/)) {
                alert.error('Please select an image file');
                return;
            }

            // Validate file size (max 2MB)
            if (file.size > 2 * 1024 * 1024) {
                alert.error('Image size should be less than 2MB');
                return;
            }

            setProfileImage(file);

            // Create preview
            const reader = new FileReader();
            reader.onloadend = () => {
                setImagePreview(reader.result);
            };
            reader.readAsDataURL(file);
        }
    };

    const uploadProfileImage = async () => {
        if (!profileImage) return;

        setUploadingImage(true);
        const formData = new FormData();
        formData.append('profile_picture', profileImage);

        try {
            const response = await api.post('/worker/profile/upload-picture', formData, {
                headers: {
                    'Content-Type': 'multipart/form-data'
                }
            });

            if (response.data.success) {
                alert.success('Profile picture updated successfully!');
                setProfileImage(null);
            }
        } catch (error) {
            console.error('Error uploading image:', error);
            alert.error('Failed to upload profile picture');
        } finally {
            setUploadingImage(false);
        }
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        setUpdating(true);
        setError('');
        setUpdateSuccess('');

        try {
            const dataToSend = {
                name: profileData.name,
                email: profileData.email,
                phone: profileData.phone,
                township: profileData.township,
                address: profileData.address,
                primary_skill: profileData.primary_skill,
                skills: profileData.skills,
                experience_years: parseInt(profileData.experience_years) || 0,
                hourly_rate_min: parseInt(profileData.hourly_rate_min) || 100,
                hourly_rate_max: parseInt(profileData.hourly_rate_max) || 300,
                available_days: profileData.available_days,
                available_hours: profileData.available_hours,
                travel_radius_km: parseInt(profileData.travel_radius_km) || 5,
                bio: profileData.bio
            };

            const response = await api.put('/worker/profile', dataToSend);

            if (response.data.success) {
                updateUser({ name: profileData.name });
                alert.success('Profile updated successfully!');
                setUpdateSuccess('Profile updated successfully!');

                // Upload image if selected
                if (profileImage) {
                    await uploadProfileImage();
                }

                setIsEditing(false);
                loadWorkerProfile();

                setTimeout(() => setUpdateSuccess(''), 3000);
            } else {
                alert.error(response.data.message || 'Failed to update profile');
            }
        } catch (error) {
            console.error('Update error:', error);
            alert.error(error.response?.data?.message || 'Network error. Please try again.');
        } finally {
            setUpdating(false);
        }
    };

    const handleCancel = () => {
        setIsEditing(false);
        setProfileData({
            name: worker.name || '',
            email: worker.email || '',
            phone: worker.phone || '',
            township: worker.township || '',
            address: worker.address || '',
            primary_skill: worker.primary_skill || '',
            skills: worker.skills || [],
            experience_years: worker.experience_years || 0,
            hourly_rate_min: worker.hourly_rate_min || 100,
            hourly_rate_max: worker.hourly_rate_max || 300,
            available_days: worker.available_days || '',
            available_hours: worker.available_hours || '',
            travel_radius_km: worker.travel_radius_km || 5,
            bio: worker.bio || ''
        });
        setNewSkill('');
        setProfileImage(null);
        setImagePreview(worker.profile_picture || null);
    };

    const handleChangePassword = async (e) => {
        e.preventDefault();

        if (passwordData.new_password !== passwordData.confirm_password) {
            alert.error('New passwords do not match');
            return;
        }

        if (passwordData.new_password.length < 8) {
            alert.error('Password must be at least 8 characters');
            return;
        }

        setUpdating(true);
        try {
            const response = await api.post('/worker/change-password', {
                current_password: passwordData.current_password,
                new_password: passwordData.new_password
            });

            if (response.data.success) {
                alert.success('Password changed successfully!');
                setPasswordData({
                    current_password: '',
                    new_password: '',
                    confirm_password: ''
                });
                setShowPasswordModal(false);
            }
        } catch (error) {
            console.error('Error changing password:', error);
            alert.error(error.response?.data?.message || 'Failed to change password');
        } finally {
            setUpdating(false);
        }
    };

    const handleDeleteAccount = async () => {
        alert.confirm(
            '⚠️ Are you sure you want to delete your account? This action cannot be undone. All your applications and data will be permanently removed.',
            async () => {
                try {
                    const response = await api.delete('/worker/account');
                    if (response.data.success) {
                        alert.success('Account deleted. Logging out...');
                        setTimeout(() => {
                            localStorage.clear();
                            window.location.href = '/';
                        }, 2000);
                    }
                } catch (error) {
                    console.error('Error deleting account:', error);
                    alert.error('Failed to delete account');
                }
            },
            null,
            'Delete Account',
            'Yes, Delete Permanently',
            'Cancel'
        );
    };

    // Safe formatting functions
    const formatRating = (rating) => {
        if (rating === null || rating === undefined) return '0.0';
        const numRating = parseFloat(rating);
        return isNaN(numRating) ? '0.0' : numRating.toFixed(1);
    };

    const formatNumber = (num) => {
        if (num === null || num === undefined) return '0';
        const parsed = parseInt(num);
        return isNaN(parsed) ? '0' : parsed.toString();
    };

    const formatCurrency = (amount) => {
        if (amount === null || amount === undefined) return '0';
        const parsed = parseFloat(amount);
        return isNaN(parsed) ? '0' : parsed.toFixed(0);
    };

    const formatPercentage = (rate) => {
        if (rate === null || rate === undefined) return '0%';
        const parsed = parseFloat(rate);
        return isNaN(parsed) ? '0%' : parsed.toFixed(1) + '%';
    };

    const handleBack = () => {
        if (fromJob && jobId) {
            navigate(`/jobs/${jobId}`);
        } else {
            navigate(-1);
        }
    };

    const handleGoToMyProfile = () => {
        if (user) {
            navigate(`/workers/${user.id}`);
        }
    };

    const getInitials = (name) => {
        if (!name) return 'W';
        return name.split(' ').map(n => n[0]).join('').toUpperCase().substring(0, 2);
    };

    if (loading) {
        return (
            <div className="loading-container">
                <div className="loading-spinner">Loading profile...</div>
            </div>
        );
    }

    if (error || !worker) {
        return (
            <div className="error-container">
                <h2>❌ Error</h2>
                <p>{error || 'Worker not found'}</p>
                <button onClick={handleBack} className="btn-primary">
                    Go Back
                </button>
            </div>
        );
    }

    const isOwnProfile = user?.id === worker.user_id;

    return (
        <div className="worker-profile-container">
            <div className="worker-profile-card">
                {/* Back Button */}
                <div className="back-navigation">
                    <button onClick={handleBack} className="back-button">
                        ← {fromJob ? `Back to Job: ${jobTitle || 'Job Details'}` : 'Back'}
                    </button>
                    {fromJob && (
                        <span className="navigation-context">
                            Viewing worker profile
                        </span>
                    )}
                </div>

                {/* Success Message */}
                {updateSuccess && (
                    <div className="success-message">
                        ✅ {updateSuccess}
                    </div>
                )}

                {/* Error Message */}
                {error && (
                    <div className="error-message">
                        ❌ {error}
                    </div>
                )}

                {/* Navigation helper - shows only when a worker is viewing another worker's profile */}
                {user && worker.user_id !== user.id && user.user_type === 'worker' && (
                    <div className="quick-action-card" style={{ 
                        marginBottom: '20px', 
                        background: '#E1F5FE',
                        borderLeft: '4px solid #0288D1'
                    }}>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '15px', flexWrap: 'wrap' }}>
                            <span style={{ fontSize: '32px' }}>👋</span>
                            <div style={{ flex: 1 }}>
                                <p style={{ margin: 0, fontWeight: 600, color: '#01579B' }}>
                                    You're viewing <strong>{worker.name}'s</strong> profile
                                </p>
                                <p style={{ margin: '5px 0 0', fontSize: '14px', color: '#0277BD' }}>
                                    Want to view or edit your own profile?
                                </p>
                            </div>
                            <button 
                                onClick={handleGoToMyProfile}
                                className="btn-primary"
                                style={{ 
                                    background: '#0288D1',
                                    whiteSpace: 'nowrap',
                                    padding: '10px 20px'
                                }}
                            >
                                👤 Go to My Profile
                            </button>
                        </div>
                    </div>
                )}

                {/* For clients viewing a worker profile - show a different message */}
                {user && worker.user_id !== user.id && user.user_type === 'client' && (
                    <div className="quick-action-card" style={{ 
                        marginBottom: '20px', 
                        background: '#FFF1E6',
                        borderLeft: '4px solid #FF6B35'
                    }}>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '15px', flexWrap: 'wrap' }}>
                            <span style={{ fontSize: '32px' }}>👷</span>
                            <div style={{ flex: 1 }}>
                                <p style={{ margin: 0, fontWeight: 600, color: '#7B341E' }}>
                                    You're viewing <strong>{worker.name}'s</strong> worker profile
                                </p>
                                <p style={{ margin: '5px 0 0', fontSize: '14px', color: '#9C4221' }}>
                                    Review their skills and ratings before hiring
                                </p>
                            </div>
                            {fromJob && jobId && (
                                <button 
                                    onClick={() => navigate(`/jobs/${jobId}`)}
                                    className="btn-primary"
                                    style={{ 
                                        background: '#FF6B35',
                                        whiteSpace: 'nowrap',
                                        padding: '10px 20px'
                                    }}
                                >
                                    ↩️ Back to Job
                                </button>
                            )}
                        </div>
                    </div>
                )}

                {/* For users not logged in */}
                {!user && (
                    <div className="quick-action-card" style={{ 
                        marginBottom: '20px', 
                        background: '#F3F4F6',
                        borderLeft: '4px solid #9CA3AF'
                    }}>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '15px', flexWrap: 'wrap' }}>
                            <span style={{ fontSize: '32px' }}>🔍</span>
                            <div style={{ flex: 1 }}>
                                <p style={{ margin: 0, fontWeight: 600, color: '#1F2937' }}>
                                    Viewing <strong>{worker.name}'s</strong> profile
                                </p>
                                <p style={{ margin: '5px 0 0', fontSize: '14px', color: '#4B5563' }}>
                                    <Link to="/login" style={{ color: '#FF6B35', fontWeight: 600 }}>Sign in</Link> to hire or apply for jobs
                                </p>
                            </div>
                        </div>
                    </div>
                )}

                {/* Profile Header */}
                <div className="profile-header">
                    <div className="profile-avatar-large">
                        {imagePreview ? (
                            <img src={imagePreview} alt="Profile" className="profile-image" />
                        ) : (
                            <div className="avatar-initials">
                                {getInitials(worker.name)}
                            </div>
                        )}
                        {isOwnProfile && (
                            <label htmlFor="profile-image-upload" className="upload-image-btn">
                                <span>📷</span>
                                <input
                                    type="file"
                                    id="profile-image-upload"
                                    accept="image/*"
                                    onChange={handleImageChange}
                                    style={{ display: 'none' }}
                                />
                            </label>
                        )}
                    </div>
                    <div className="profile-title">
                        <h1>{worker.name || 'Unknown Worker'}</h1>
                        <p className="worker-phone">{worker.phone}</p>
                        <p className="worker-location">
                            <span className="location-icon">📍</span>
                            {worker.township || 'Location not specified'}
                        </p>
                        <div className="worker-badges">
                            {worker.is_verified && (
                                <span className="badge verified">✓ Verified</span>
                            )}
                            <span className="badge level">
                                Level {worker.verification_level || 0}
                            </span>
                        </div>
                    </div>

                    {/* Edit button - only shows on own profile */}
                    {isOwnProfile && !isEditing && (
                        <button 
                            className="btn-edit"
                            onClick={() => setIsEditing(true)}
                        >
                            ✎ Edit Profile
                        </button>
                    )}

                    {/* Cancel Edit button - only shows when editing own profile */}
                    {isOwnProfile && isEditing && (
                        <button 
                            className="btn-cancel-edit"
                            onClick={handleCancel}
                        >
                            ✕ Cancel Editing
                        </button>
                    )}
                </div>

                {profileImage && isOwnProfile && (
                    <div className="image-preview-actions">
                        <button onClick={uploadProfileImage} className="btn-save-image" disabled={uploadingImage}>
                            {uploadingImage ? 'Uploading...' : 'Save New Image'}
                        </button>
                        <button onClick={() => {
                            setProfileImage(null);
                            setImagePreview(worker.profile_picture || null);
                        }} className="btn-cancel-image">
                            Cancel
                        </button>
                    </div>
                )}

                {/* Profile Tabs */}
                <div className="profile-tabs">
                    <button 
                        className={`tab-btn ${activeTab === 'profile' ? 'active' : ''}`}
                        onClick={() => setActiveTab('profile')}
                    >
                        👤 Profile Information
                    </button>
                    <button 
                        className={`tab-btn ${activeTab === 'skills' ? 'active' : ''}`}
                        onClick={() => setActiveTab('skills')}
                    >
                        🛠️ Skills & Rates
                    </button>
                    <button 
                        className={`tab-btn ${activeTab === 'security' ? 'active' : ''}`}
                        onClick={() => setActiveTab('security')}
                    >
                        🔒 Security Settings
                    </button>
                </div>

                {activeTab === 'profile' && (
                    <form onSubmit={handleSubmit} className="profile-form">
                        <h2>Personal Information</h2>

                        <div className="form-row">
                            <div className="form-group">
                                <label>Full Name</label>
                                <input
                                    type="text"
                                    name="name"
                                    value={profileData.name}
                                    onChange={handleInputChange}
                                    disabled={!isEditing}
                                    required
                                />
                            </div>

                            <div className="form-group">
                                <label>Email Address</label>
                                <input
                                    type="email"
                                    name="email"
                                    value={profileData.email}
                                    onChange={handleInputChange}
                                    disabled={!isEditing}
                                />
                            </div>
                        </div>

                        <div className="form-row">
                            <div className="form-group">
                                <label>Phone Number</label>
                                <input
                                    type="tel"
                                    name="phone"
                                    value={profileData.phone}
                                    onChange={handleInputChange}
                                    disabled={!isEditing}
                                    required
                                />
                            </div>

                            <div className="form-group">
                                <label>Township</label>
                                <input
                                    type="text"
                                    name="township"
                                    value={profileData.township}
                                    onChange={handleInputChange}
                                    disabled={!isEditing}
                                    placeholder="e.g., Soweto"
                                />
                            </div>
                        </div>

                        <div className="form-group">
                            <label>Street Address</label>
                            <input
                                type="text"
                                name="address"
                                value={profileData.address}
                                onChange={handleInputChange}
                                disabled={!isEditing}
                                placeholder="Your physical address"
                            />
                        </div>

                        {isEditing && (
                            <div className="profile-actions">
                                <button 
                                    type="button" 
                                    className="btn-change-password"
                                    onClick={() => setShowPasswordModal(true)}
                                >
                                    🔑 Change Password
                                </button>
                                <button 
                                    type="submit" 
                                    className="btn-save-profile"
                                    disabled={updating}
                                >
                                    {updating ? 'Saving...' : 'Save Changes'}
                                </button>
                            </div>
                        )}
                    </form>
                )}

                {activeTab === 'skills' && (
                    <div className="skills-tab">
                        <h2>Skills & Rates</h2>

                        {isEditing ? (
                            <div className="skills-edit-form">
                                <div className="form-group">
                                    <label>Primary Skill</label>
                                    <select
                                        name="primary_skill"
                                        value={profileData.primary_skill}
                                        onChange={handleInputChange}
                                    >
                                        <option value="">Select primary skill</option>
                                        <option value="Gardening">Gardening</option>
                                        <option value="Cleaning">Cleaning</option>
                                        <option value="Plumbing">Plumbing</option>
                                        <option value="Electrical">Electrical</option>
                                        <option value="Painting">Painting</option>
                                        <option value="Building">Building</option>
                                        <option value="Carpentry">Carpentry</option>
                                        <option value="Moving">Moving</option>
                                        <option value="Delivery">Delivery</option>
                                        <option value="Handyman">Handyman</option>
                                    </select>
                                </div>

                                <div className="form-group">
                                    <label>Years of Experience</label>
                                    <input
                                        type="number"
                                        name="experience_years"
                                        value={profileData.experience_years}
                                        onChange={handleInputChange}
                                        min="0"
                                        max="50"
                                    />
                                </div>

                                <div className="form-group">
                                    <label>Other Skills</label>
                                    <div className="skills-input-group">
                                        <input
                                            type="text"
                                            value={newSkill}
                                            onChange={(e) => setNewSkill(e.target.value)}
                                            placeholder="Enter a skill"
                                            className="skill-input"
                                        />
                                        <button 
                                            type="button"
                                            className="btn-add-skill"
                                            onClick={handleAddSkill}
                                        >
                                            + Add
                                        </button>
                                    </div>

                                    <div className="skills-list-edit">
                                        {profileData.skills.map((skill, index) => (
                                            <div key={index} className="skill-item">
                                                <span>{skill}</span>
                                                <button 
                                                    type="button"
                                                    className="btn-remove-skill"
                                                    onClick={() => handleRemoveSkill(skill)}
                                                >
                                                    ×
                                                </button>
                                            </div>
                                        ))}
                                        {profileData.skills.length === 0 && (
                                            <p className="no-skills">No additional skills added yet</p>
                                        )}
                                    </div>
                                </div>

                                <div className="form-row">
                                    <div className="form-group">
                                        <label>Hourly Rate Min (R)</label>
                                        <input
                                            type="number"
                                            name="hourly_rate_min"
                                            value={profileData.hourly_rate_min}
                                            onChange={handleInputChange}
                                            min="0"
                                            step="50"
                                        />
                                    </div>

                                    <div className="form-group">
                                        <label>Hourly Rate Max (R)</label>
                                        <input
                                            type="number"
                                            name="hourly_rate_max"
                                            value={profileData.hourly_rate_max}
                                            onChange={handleInputChange}
                                            min="0"
                                            step="50"
                                        />
                                    </div>
                                </div>

                                <div className="form-group">
                                    <label>Travel Radius (km)</label>
                                    <input
                                        type="number"
                                        name="travel_radius_km"
                                        value={profileData.travel_radius_km}
                                        onChange={handleInputChange}
                                        min="1"
                                        max="100"
                                    />
                                </div>

                                <div className="form-group">
                                    <label>Available Days</label>
                                    <input
                                        type="text"
                                        name="available_days"
                                        value={profileData.available_days}
                                        onChange={handleInputChange}
                                        placeholder="e.g., Monday - Friday"
                                    />
                                </div>

                                <div className="form-group">
                                    <label>Available Hours</label>
                                    <input
                                        type="text"
                                        name="available_hours"
                                        value={profileData.available_hours}
                                        onChange={handleInputChange}
                                        placeholder="e.g., 9am - 5pm"
                                    />
                                </div>

                                <div className="form-group">
                                    <label>Bio / Introduction</label>
                                    <textarea
                                        name="bio"
                                        value={profileData.bio}
                                        onChange={handleInputChange}
                                        placeholder="Tell clients about yourself..."
                                        rows="4"
                                    />
                                </div>
                            </div>
                        ) : (
                            <div className="skills-view">
                                <div className="skills-section">
                                    <h3>Primary Skill</h3>
                                    <p className="skill-primary">{worker.primary_skill || 'Not specified'}</p>
                                </div>

                                <div className="skills-section">
                                    <h3>Other Skills</h3>
                                    <div className="skills-list">
                                        {worker.skills?.length > 0 ? (
                                            worker.skills.map((skill, index) => (
                                                <span key={index} className="skill-tag">{skill}</span>
                                            ))
                                        ) : (
                                            <p className="no-skills">No additional skills listed</p>
                                        )}
                                    </div>
                                </div>

                                <div className="skills-section">
                                    <h3>Experience</h3>
                                    <p>{worker.experience_years || 0} years</p>
                                </div>

                                <div className="skills-section">
                                    <h3>Rates</h3>
                                    <p>R{worker.hourly_rate_min || 100} - R{worker.hourly_rate_max || 300} per hour</p>
                                </div>

                                <div className="skills-section">
                                    <h3>Travel Radius</h3>
                                    <p>{worker.travel_radius_km || 5} km</p>
                                </div>

                                <div className="skills-section">
                                    <h3>Availability</h3>
                                    <p><strong>Days:</strong> {worker.available_days || 'Flexible'}</p>
                                    <p><strong>Hours:</strong> {worker.available_hours || 'Flexible'}</p>
                                </div>

                                {worker.bio && (
                                    <div className="skills-section">
                                        <h3>About</h3>
                                        <p className="bio-text">{worker.bio}</p>
                                    </div>
                                )}
                            </div>
                        )}

                        {isEditing && (
                            <div className="profile-actions">
                                <button 
                                    type="button" 
                                    className="btn-cancel"
                                    onClick={handleCancel}
                                >
                                    Cancel
                                </button>
                                <button 
                                    type="button" 
                                    className="btn-save-profile"
                                    onClick={handleSubmit}
                                    disabled={updating}
                                >
                                    {updating ? 'Saving...' : 'Save Skills'}
                                </button>
                            </div>
                        )}
                    </div>
                )}

                {activeTab === 'security' && (
                    <div className="security-settings">
                        <h2>Security Settings</h2>

                        <div className="settings-section">
                            <h3>Password Management</h3>
                            <div className="setting-item">
                                <div className="setting-info">
                                    <strong>Change Password</strong>
                                    <p>Update your password regularly for security</p>
                                </div>
                                <button 
                                    className="btn-change-password-small"
                                    onClick={() => setShowPasswordModal(true)}
                                >
                                    Change
                                </button>
                            </div>
                        </div>

                        <div className="danger-zone">
                            <h3>⚠️ Danger Zone</h3>
                            <div className="danger-item">
                                <div className="danger-info">
                                    <strong>Delete Account</strong>
                                    <p>Permanently delete your account and all your data</p>
                                </div>
                                <button 
                                    className="btn-delete-account"
                                    onClick={() => setShowDeleteModal(true)}
                                >
                                    Delete Account
                                </button>
                            </div>
                        </div>
                    </div>
                )}
                {/* Contact Info Section - Only visible if hired or own profile */}
                {(isOwnProfile || (user?.user_type === 'client' && canHire)) ? (
                    <div className="contact-info-section">
                        <h3>📞 Contact Information</h3>
                        <p><strong>Phone:</strong> {worker.phone}</p>
                        {worker.email && <p><strong>Email:</strong> {worker.email}</p>}
                    </div>
                ) : user?.user_type === 'client' && !canHire && (
                    <div className="contact-hidden-message">
                        <p>🔒 Contact information is hidden</p>
                        <p>Hire this worker to reveal contact details</p>
                        <Link to={`/jobs/${location.state?.jobId}`} className="btn-back-to-job">
                            Back to Job
                        </Link>
                    </div>
                )}                

                {/* Performance Stats (always visible for everyone) */}
                <div className="performance-stats">
                    <h3>Performance Stats</h3>
                    <div className="stats-grid">
                        <div className="stat-item">
                            <span className="stat-value">{formatRating(worker.rating)}</span>
                            <span className="stat-label">Rating</span>
                        </div>
                        <div className="stat-item">
                            <span className="stat-value">{formatNumber(worker.completed_jobs)}</span>
                            <span className="stat-label">Jobs Done</span>
                        </div>
                        <div className="stat-item">
                            <span className="stat-value">{formatNumber(worker.total_jobs)}</span>
                            <span className="stat-label">Total Jobs</span>
                        </div>
                        <div className="stat-item">
                            <span className="stat-value">{formatPercentage(worker.cancellation_rate)}</span>
                            <span className="stat-label">Cancellation Rate</span>
                        </div>
                    </div>
                </div>

                {/* Reviews Section (always view-only) */}
                {worker.reviews?.length > 0 && (
                    <div className="reviews-section">
                        <h3>Recent Reviews</h3>
                        <div className="reviews-list">
                            {worker.reviews.slice(0, 3).map((review, index) => (
                                <div key={index} className="review-item">
                                    <div className="review-header">
                                        <span className="reviewer">{review.reviewer_name}</span>
                                        <span className="review-rating">{'⭐'.repeat(review.rating)}</span>
                                    </div>
                                    <p className="review-comment">{review.comment}</p>
                                </div>
                            ))}
                        </div>
                    </div>
                )}
            </div>

            {/* Change Password Modal */}
            {showPasswordModal && (
                <div className="modal-overlay" onClick={() => setShowPasswordModal(false)}>
                    <div className="password-modal" onClick={e => e.stopPropagation()}>
                        <div className="modal-header">
                            <h2>🔑 Change Password</h2>
                            <button className="modal-close" onClick={() => setShowPasswordModal(false)}>×</button>
                        </div>

                        <form onSubmit={handleChangePassword} className="password-form">
                            <div className="form-group">
                                <label>Current Password</label>
                                <input
                                    type="password"
                                    name="current_password"
                                    value={passwordData.current_password}
                                    onChange={handlePasswordChange}
                                    required
                                />
                            </div>

                            <div className="form-group">
                                <label>New Password</label>
                                <input
                                    type="password"
                                    name="new_password"
                                    value={passwordData.new_password}
                                    onChange={handlePasswordChange}
                                    required
                                    minLength="8"
                                />
                            </div>

                            <div className="form-group">
                                <label>Confirm New Password</label>
                                <input
                                    type="password"
                                    name="confirm_password"
                                    value={passwordData.confirm_password}
                                    onChange={handlePasswordChange}
                                    required
                                />
                            </div>

                            <div className="password-requirements">
                                <p>Password must:</p>
                                <ul>
                                    <li className={passwordData.new_password.length >= 8 ? 'valid' : ''}>
                                        ✓ Be at least 8 characters
                                    </li>
                                    <li className={/[A-Z]/.test(passwordData.new_password) ? 'valid' : ''}>
                                        ✓ Contain an uppercase letter
                                    </li>
                                    <li className={/[0-9]/.test(passwordData.new_password) ? 'valid' : ''}>
                                        ✓ Contain a number
                                    </li>
                                </ul>
                            </div>

                            <div className="modal-actions">
                                <button type="button" className="btn-cancel" onClick={() => setShowPasswordModal(false)}>
                                    Cancel
                                </button>
                                <button type="submit" className="btn-change" disabled={updating}>
                                    {updating ? 'Changing...' : 'Change Password'}
                                </button>
                            </div>
                        </form>
                    </div>
                </div>
            )}

            {/* Delete Account Modal */}
            {showDeleteModal && (
                <div className="modal-overlay" onClick={() => setShowDeleteModal(false)}>
                    <div className="delete-modal" onClick={e => e.stopPropagation()}>
                        <div className="modal-header warning">
                            <h2>⚠️ Delete Account</h2>
                            <button className="modal-close" onClick={() => setShowDeleteModal(false)}>×</button>
                        </div>

                        <div className="modal-body">
                            <p className="warning-text">
                                This action is <strong>permanent</strong>. All your applications, job history, and personal data will be deleted.
                            </p>

                            <button 
                                className="btn-delete-confirm"
                                onClick={handleDeleteAccount}
                            >
                                Yes, Delete My Account
                            </button>
                            <button 
                                className="btn-cancel"
                                onClick={() => setShowDeleteModal(false)}
                            >
                                Cancel
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default WorkerProfile;
